            continue

        # Check for section headers
        if "Capital Improvement Projects (Design)" in line:
            in_design_section = True
            continue

        # Stop if we hit another section
        if in_design_section:
            if "Capital Improvement Projects" in line and "(Design)" not in line:
                in_design_section = False
            elif "Disaster Recovery Projects" in line:
                in_design_section = False

        if in_design_section:
            # Check for bad lines
            # Using simple string checks to avoid unicode issues in source code
            if "(cid:" in line:
                continue
            # Check for bullet points (common unicode bullets)
            # Just skip lines starting with non-alphanumeric chars if possible, but project names start with letters or numbers
            if not line[0].isalnum():
                continue

            if line.lower().startswith("page ") or "agenda item" in line.lower():
                continue
            if line.startswith("To:") or line.startswith("From:") or line.startswith("Subject:"):
                continue
            if "Updates:" in line or "Project Schedule:" in line or "Estimated Schedule:" in line:
                continue
            if "Complete Design:" in line or "Begin Construction:" in line or "Advertise:" in line:
                continue
            if "Project Description:" in line or "Project Updates:" in line:
                continue

            extracted_design_projects.append(line)

# Remove duplicates
extracted_design_projects = list(set(extracted_design_projects))

print(f"DEBUG: Extracted {len(extracted_design_projects)} potential design projects.")

# Count matches
match_count = 0
matches = []
# Create a lower-case mapping for fuzzy matching if needed
funded_projects_lower = {k.lower(): k for k in funded_projects}

for proj in extracted_design_projects:
    proj_clean = proj.strip()
    # Exact match
    if proj_clean in funded_projects:
        match_count += 1
        matches.append(proj_clean)
    # Fuzzy match (case insensitive)
    elif proj_clean.lower() in funded_projects_lower:
        match_count += 1
        matches.append(funded_projects_lower[proj_clean.lower()])

print("__RESULT__:")
print(json.dumps({"count": match_count, "matches": matches, "extracted": extracted_design_projects}))
"}

