{"code":"import json

with open(locals()['var_function-call-7721797773547696454'], 'r') as f:
    funding_data = json.load(f)
with open(locals()['var_function-call-11187982915613525112'], 'r') as f:
    civic_docs = json.load(f)

funded_projects = {}
for item in funding_data:
    try:
        amount = float(item['Amount'])
        if amount > 50000:
            funded_projects[item['Project_Name'].strip()] = amount
    except ValueError:
        pass

design_lines = []
for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.splitlines()
    in_design = False
    for line in lines:
        line = line.strip()
        if not line: continue
        if 'Capital Improvement Projects (Design)' in line:
            in_design = True
            continue
        if in_design:
            if 'Capital Improvement Projects' in line and '(Design)' not in line:
                in_design = False
            elif 'Disaster Recovery Projects' in line:
                in_design = False
        if in_design:
            if line.lower().startswith('page') or 'agenda item' in line.lower(): continue
            if any(x in line for x in ['Updates:', 'Schedule:', 'To:', 'From:', 'Subject:', 'Complete Design:', 'Advertise:', 'Construction:']): continue
            if not line[0].isalnum(): continue
            design_lines.append(line)

design_lines = list(set(design_lines))

matches = []
used_funding = set()

# 1. Exact Match
for line in design_lines:
    if line in funded_projects:
        matches.append((line, line))
        used_funding.add(line)

# 2. Case Insensitive
for line in design_lines:
    if any(m[0] == line for m in matches): continue
    for fp in funded_projects:
        if fp in used_funding: continue
        if fp.lower() == line.lower():
            matches.append((line, fp))
            used_funding.add(fp)
            break

# 3. Containment
for line in design_lines:
    if any(m[0] == line for m in matches): continue
    for fp in funded_projects:
        if fp in used_funding: continue
        if fp in line or line in fp:
            matches.append((line, fp))
            used_funding.add(fp)
            break

# 4. Token Overlap (>= 3 words)
for line in design_lines:
    if any(m[0] == line for m in matches): continue
    line_tokens = set(line.lower().replace('&','').split())
    best_fp = None
    max_overlap = 0
    for fp in funded_projects:
        if fp in used_funding: continue
        fp_tokens = set(fp.lower().replace('&','').split())
        overlap = len(line_tokens & fp_tokens)
        if overlap > max_overlap:
            max_overlap = overlap
            best_fp = fp

    if max_overlap >= 3 and best_fp:
        matches.append((line, best_fp))
        used_funding.add(best_fp)

print('__RESULT__:')
print(json.dumps({'count': len(matches), 'matches': matches}))
"}

