            if any(x in line for x in ['Updates:', 'Schedule:', 'To:', 'From:', 'Subject:', 'Complete Design:', 'Advertise:', 'Construction:']): continue
            if not line[0].isalnum(): continue
            design_lines.append(line)

design_lines = list(set(design_lines))

matches = []
used_funding = set()

# 1. Exact Match
for line in design_lines:
    if line in funded_projects:
        matches.append((line, line))
        used_funding.add(line)

# 2. Case Insensitive
for line in design_lines:
    if any(m[0] == line for m in matches): continue
    for fp in funded_projects:
        if fp in used_funding: continue
        if fp.lower() == line.lower():
            matches.append((line, fp))
            used_funding.add(fp)
            break

# 3. Containment
for line in design_lines:
    if any(m[0] == line for m in matches): continue
    for fp in funded_projects:
        if fp in used_funding: continue
        if fp in line or line in fp:
            matches.append((line, fp))
            used_funding.add(fp)
            break

# 4. Token Overlap (>= 3 words)
for line in design_lines:
    if any(m[0] == line for m in matches): continue
    line_tokens = set(line.lower().replace('&','').split())
    best_fp = None
    max_overlap = 0
    for fp in funded_projects:
        if fp in used_funding: continue
        fp_tokens = set(fp.lower().replace('&','').split())
        overlap = len(line_tokens & fp_tokens)
        if overlap > max_overlap:
            max_overlap = overlap
            best_fp = fp

    if max_overlap >= 3 and best_fp:
        matches.append((line, best_fp))
        used_funding.add(best_fp)

print('__RESULT__:')
print(json.dumps({'count': len(matches), 'matches': matches}))
